/* Standalone browser build: simulator + app. */
const TARGETS = {
  order1: 30,
  order2: 30,
  cash: 30,
  present: 60,
  total: 90,
};

const STATUS_THRESHOLDS = {
  yellow: 90,
  red: 120,
};

const POSITION_META = {
  lane1_pre1: { next: 'order1' },
  order1: { next: 'lane1_post', station: 'order1' },
  lane1_post: { next: 'gap_cash_entry' },

  lane2_pre1: { next: 'order2' },
  order2: { next: 'lane2_merge', station: 'order2' },
  lane2_merge: { next: 'gap_cash_entry' },

  gap_cash_entry: { next: 'cash' },
  cash: { next: 'gap_present1', station: 'cash' },
  gap_present1: { next: 'present' },
  present: { next: 'exit', station: 'present' },
};

const STATIONS = new Set(['order1', 'order2', 'cash', 'present']);

class DriveThruSimulator {
  constructor(savedState = null) {
    this.now = 0;
    this.nextCarId = 1;
    this.activeCars = [];
    this.completedCars = [];
    this.statusMessage = 'Ready.';
    if (savedState) this.load(savedState);
  }

  reset() {
    this.now = 0;
    this.nextCarId = 1;
    this.activeCars = [];
    this.completedCars = [];
    this.statusMessage = 'Ready.';
  }

  serialize() {
    return { now: this.now, nextCarId: this.nextCarId, activeCars: this.activeCars, completedCars: this.completedCars, statusMessage: this.statusMessage };
  }

  load(state) {
    this.now = Number(state.now) || 0;
    this.nextCarId = Number(state.nextCarId) || 1;
    this.activeCars = Array.isArray(state.activeCars) ? state.activeCars : [];
    this.completedCars = Array.isArray(state.completedCars) ? state.completedCars : [];
    this.statusMessage = state.statusMessage || 'Ready.';
  }

  carAt(position) { return this.activeCars.find((car) => car.position === position) || null; }

  addCar(lane) {
    const spawn = lane === 1 ? 'lane1_pre1' : 'lane2_pre1';
    if (this.carAt(spawn)) return { ok: false, reason: `Lane ${lane} spawn is full.` };
    const car = {
      id: this.nextCarId++, lane, position: spawn, positionEnteredAt: this.now,
      totalStartedAt: null, orderReleaseAt: null, releaseRequested: false,
      thresholds: { yellow: false, red: false },
      timings: { order1: null, order2: null, cash: null, present: null, total: null },
      completedAt: null,
    };
    this.activeCars.push(car);
    this.statusMessage = `Car #${car.id} added to Lane ${lane}.`;
    return { ok: true, car, events: [{ type: lane === 1 ? 'lane1-entry' : 'lane2-entry', carId: car.id }] };
  }

  releaseStation(station) {
    const car = this.carAt(station);
    if (!car) {
      this.statusMessage = `No car at ${station}.`;
      return { ok: false, reason: `No car at ${station}.` };
    }
    if (car.releaseRequested) {
      this.statusMessage = `Car #${car.id} is already ready to leave ${station}.`;
      return { ok: true, car, alreadyRequested: true };
    }
    car.releaseRequested = true;
    car.orderReleaseAt = STATIONS.has(station) ? this.now : car.orderReleaseAt;
    this.statusMessage = `Car #${car.id} is ready to leave ${station} when the path clears.`;
    return { ok: true, car };
  }

  stationElapsed(car) { return this.now - car.positionEnteredAt; }
  totalElapsed(car) { return car.totalStartedAt == null ? 0 : this.now - car.totalStartedAt; }
  getCarsInLaneCount() { return this.activeCars.length; }
  getLongestCurrentTotal() { let longest = 0; for (const car of this.activeCars) longest = Math.max(longest, this.totalElapsed(car)); return longest; }

  tick(seconds = 1) {
    const allEvents = [];
    for (let i = 0; i < seconds; i += 1) {
      this.now += 1;
      const events = [];
      this.processMovement(events);
      this.processThresholds(events);
      allEvents.push(...events);
    }
    return allEvents;
  }

  processThresholds(events) {
    for (const car of this.activeCars) {
      const total = this.totalElapsed(car);
      if (car.totalStartedAt != null && !car.thresholds.yellow && total >= STATUS_THRESHOLDS.yellow) {
        car.thresholds.yellow = true;
        events.push({ type: 'yellow-threshold', carId: car.id, lane: car.lane });
      }
      if (car.totalStartedAt != null && !car.thresholds.red && total >= STATUS_THRESHOLDS.red) {
        car.thresholds.red = true;
        events.push({ type: 'red-threshold', carId: car.id, lane: car.lane });
      }
    }
  }

  canLeaveStation(car) {
    const meta = POSITION_META[car.position];
    if (!meta.station) return true;
    return !!car.releaseRequested;
  }

  canMoveFrom(position) {
    const car = this.carAt(position);
    if (!car) return false;
    if ((this.now - car.positionEnteredAt) < 1) return false;
    const meta = POSITION_META[position];
    if (!meta.next) return false;
    if (meta.station) return this.canLeaveStation(car);
    return true;
  }

  processMovement(events) {
    const occupiedStart = new Set(this.activeCars.map((car) => car.position));
    const plannedMoves = [];
    const isEmptyAtStart = (position) => !occupiedStart.has(position);
    const planMove = (car, target) => plannedMoves.push({ carId: car.id, from: car.position, to: target });

    const presentCar = this.carAt('present');
    if (presentCar && this.canMoveFrom('present')) planMove(presentCar, 'exit');

    const gapPresentCar = this.carAt('gap_present1');
    if (gapPresentCar && this.canMoveFrom('gap_present1') && isEmptyAtStart('present')) planMove(gapPresentCar, 'present');

    const cashCar = this.carAt('cash');
    if (cashCar && this.canMoveFrom('cash') && isEmptyAtStart('gap_present1')) planMove(cashCar, 'gap_present1');

    const preCashCar = this.carAt('gap_cash_entry');
    if (preCashCar && this.canMoveFrom('gap_cash_entry') && isEmptyAtStart('cash')) planMove(preCashCar, 'cash');

    const mergeContenders = [];
    const lane2MergeCar = this.carAt('lane2_merge');
    if (lane2MergeCar && this.canMoveFrom('lane2_merge')) mergeContenders.push(lane2MergeCar);
    const lane1PostCar = this.carAt('lane1_post');
    if (lane1PostCar && this.canMoveFrom('lane1_post')) mergeContenders.push(lane1PostCar);
    if (mergeContenders.length && isEmptyAtStart('gap_cash_entry')) {
      mergeContenders.sort((a, b) => {
        const ap = a.orderReleaseAt ?? this.now;
        const bp = b.orderReleaseAt ?? this.now;
        if (ap !== bp) return ap - bp;
        return a.id - b.id;
      });
      planMove(mergeContenders[0], 'gap_cash_entry');
    }

    const order2Car = this.carAt('order2');
    if (order2Car && this.canMoveFrom('order2') && isEmptyAtStart('lane2_merge')) planMove(order2Car, 'lane2_merge');

    const order1Car = this.carAt('order1');
    if (order1Car && this.canMoveFrom('order1') && isEmptyAtStart('lane1_post')) planMove(order1Car, 'lane1_post');

    const lane2PreCar = this.carAt('lane2_pre1');
    if (lane2PreCar && this.canMoveFrom('lane2_pre1') && isEmptyAtStart('order2')) planMove(lane2PreCar, 'order2');

    const lane1PreCar = this.carAt('lane1_pre1');
    if (lane1PreCar && this.canMoveFrom('lane1_pre1') && isEmptyAtStart('order1')) planMove(lane1PreCar, 'order1');

    if (!plannedMoves.length) return;

    for (const move of plannedMoves) {
      const car = this.activeCars.find((active) => active.id === move.carId);
      if (!car) continue;
      const previous = move.from;
      const target = move.to;
      const previousMeta = POSITION_META[previous];

      if (previousMeta.station) {
        const elapsed = this.now - car.positionEnteredAt;
        car.timings[previous] = elapsed;
        car.releaseRequested = false;
        if (previous === 'order1' || previous === 'order2') car.totalStartedAt = this.now;
      }

      if (target === 'exit') {
        car.timings.total = car.totalStartedAt != null ? this.now - car.totalStartedAt : 0;
        car.completedAt = this.now;
        this.completedCars.unshift({ ...car });
        this.activeCars = this.activeCars.filter((active) => active.id !== car.id);
        events.push({ type: 'car-completed', carId: car.id, lane: car.lane });
        this.statusMessage = `Car #${car.id} completed the drive thru.`;
      } else {
        car.position = target;
        car.positionEnteredAt = this.now;
        if (previous === 'order1' || previous === 'order2') car.orderReleaseAt = this.now;
        if (target === 'cash') car.orderReleaseAt = null;
        events.push({ type: 'car-moved', carId: car.id, from: previous, to: target });
      }
    }
  }
}

function computeScoreboard(completedCars) {
  const onlyCompleted = completedCars || [];
  const lane1Completed = onlyCompleted.filter((car) => car.lane === 1);
  const lane2Completed = onlyCompleted.filter((car) => car.lane === 2);
  const avg = (values) => values.length ? values.reduce((sum, value) => sum + value, 0) / values.length : 0;
  const underPct = (values, target) => !values.length ? 0 : Math.round((values.filter((value) => value <= target).length / values.length) * 100);
  const lane1OrderValues = lane1Completed.map((car) => car.timings.order1).filter((v) => Number.isFinite(v));
  const lane2OrderValues = lane2Completed.map((car) => car.timings.order2).filter((v) => Number.isFinite(v));
  const cashValues = onlyCompleted.map((car) => car.timings.cash).filter((v) => Number.isFinite(v));
  const presentValues = onlyCompleted.map((car) => car.timings.present).filter((v) => Number.isFinite(v));
  const totalValues = onlyCompleted.map((car) => car.timings.total).filter((v) => Number.isFinite(v));
  return {
    order1: { avg: avg(lane1OrderValues), pct: underPct(lane1OrderValues, TARGETS.order1) },
    order2: { avg: avg(lane2OrderValues), pct: underPct(lane2OrderValues, TARGETS.order2) },
    cash: { avg: avg(cashValues), pct: underPct(cashValues, TARGETS.cash) },
    present: { avg: avg(presentValues), pct: underPct(presentValues, TARGETS.present) },
    total: { avg: avg(totalValues), pct: underPct(totalValues, TARGETS.total) },
  };
}


const STORAGE_KEY = 'drive-thru-timer-map-v2';
const $ = (selector) => document.querySelector(selector);
const $$ = (selector) => [...document.querySelectorAll(selector)];



const MAP_SIZE = { width: 1196, height: 478 };
const POSITION_UI = {
  // Shared top path, moving right-to-left across the grey road in the screenshot.
  present: { x: 172, y: 131, rotation: 180 },
  gap_present1: { x: 348, y: 131, rotation: 180 },
  cash: { x: 522, y: 131, rotation: 180 },
  gap_cash_entry: { x: 697, y: 131, rotation: 180 },

  // Lane 2: one hidden/entry space before Order 2, Order 2, then one forward space before the merge.
  lane2_merge: { x: 872, y: 131, rotation: 180 },
  order2: { x: 1048, y: 131, rotation: 180 },
  lane2_pre1: { x: 1168, y: 131, rotation: 180 },

  // Lane 1: one hidden/entry space before Order 1, Order 1, then the diagonal merge space.
  lane1_post: { x: 845, y: 280, rotation: -130 },
  order1: { x: 1048, y: 342, rotation: 180 },
  lane1_pre1: { x: 1168, y: 342, rotation: 180 },
};

const simulator = new DriveThruSimulator(loadState());
let soundsEnabled = true;
let soundReady = false;
let audioContext = null;
const decodedSounds = new Map();

const CAR_IMAGES = {"green": "data:image/png;base64,", "yellow": "data:image/png;base64,", "red": "data:image/png;base64,"};

const SOUND_DATA = {"lane1Entry": {"mime": "audio/wav", "base64": ""}, "lane2Entry": {"mime": "audio/mpeg", "base64": ""}, "yellow": {"mime": "audio/wav", "base64": ""}, "red": {"mime": "audio/wav", "base64": ""}};

function saveState() {
  localStorage.setItem(STORAGE_KEY, JSON.stringify(simulator.serialize()));
}

function loadState() {
  const raw = localStorage.getItem(STORAGE_KEY);
  if (!raw) return null;
  try {
    return JSON.parse(raw);
  } catch {
    return null;
  }
}

function formatTime(seconds) {
  const safe = Math.max(0, Math.round(seconds || 0));
  const mins = Math.floor(safe / 60);
  const secs = safe % 60;
  return `${mins}:${String(secs).padStart(2, '0')}`;
}

function statusColourForPct(pct) {
  if (pct >= 75) return 'pct-good';
  if (pct >= 50) return 'pct-mid';
  return 'pct-bad';
}

function avgClassForKey(key, seconds) {
  if (key === 'order1' || key === 'order2' || key === 'cash') {
    if (seconds < 30) return 'avg-good';
    if (seconds <= 45) return 'avg-mid';
    return 'avg-bad';
  }
  if (key === 'present') {
    if (seconds < 60) return 'avg-good';
    if (seconds <= 90) return 'avg-mid';
    return 'avg-bad';
  }
  if (key === 'total') {
    if (seconds < 90) return 'avg-good';
    if (seconds < 120) return 'avg-mid';
    return 'avg-bad';
  }
  return 'avg-good';
}

function statusFromTotal(total) {
  if (total >= STATUS_THRESHOLDS.red) return 'red';
  if (total >= STATUS_THRESHOLDS.yellow) return 'yellow';
  return 'green';
}

function carStatus(car) {
  return statusFromTotal(simulator.totalElapsed(car));
}

function carImageForStatus(status) {
  return CAR_IMAGES[status] || CAR_IMAGES.green;
}

function getAudioContext() {
  const AudioContextClass = window.AudioContext || window.webkitAudioContext;
  if (!AudioContextClass) {
    throw new Error('This browser does not support the Web Audio API.');
  }
  if (!audioContext) {
    audioContext = new AudioContextClass();
  }
  return audioContext;
}

function base64ToArrayBuffer(base64) {
  const binary = window.atob(base64);
  const length = binary.length;
  const bytes = new Uint8Array(length);
  for (let i = 0; i < length; i += 1) {
    bytes[i] = binary.charCodeAt(i);
  }
  return bytes.buffer;
}

async function prepareSounds() {
  if (soundReady) return true;

  try {
    const context = getAudioContext();
    if (context.state === 'suspended') {
      await context.resume();
    }

    for (const [key, file] of Object.entries(SOUND_DATA)) {
      if (decodedSounds.has(key)) continue;
      const arrayBuffer = base64ToArrayBuffer(file.base64);
      const decoded = await context.decodeAudioData(arrayBuffer.slice(0));
      decodedSounds.set(key, decoded);
    }

    soundReady = true;
    $('#soundStatus').textContent = 'Sounds enabled';
    return true;
  } catch (error) {
    $('#soundStatus').textContent = 'Sound setup failed';
    setStatus(`Sound setup failed: ${error.message || error}`);
    return false;
  }
}

async function unlockAudio() {
  soundsEnabled = true;
  try {
    const context = getAudioContext();
    if (context.state === 'suspended') {
      await context.resume();
    }
    const ok = await prepareSounds();
    if (ok) {
      $('#soundStatus').textContent = 'Sounds enabled';
    }
    return ok;
  } catch (error) {
    $('#soundStatus').textContent = 'Sound blocked';
    setStatus(`Sound was blocked by the browser: ${error.message || error}`);
    return false;
  }
}

async function enableSounds() {
  soundsEnabled = true;
  const ok = await unlockAudio();
  $('#soundStatus').textContent = ok ? 'Sounds enabled' : 'Sound blocked';
  setStatus(ok ? 'Sounds enabled. Try the Test Sound button to confirm volume.' : 'Sound could not be enabled. Try clicking Enable Sounds again.');
}

function playDecodedBuffer(buffer) {
  return new Promise((resolve, reject) => {
    try {
      const context = getAudioContext();
      const source = context.createBufferSource();
      const gain = context.createGain();
      gain.gain.value = 1;
      source.buffer = buffer;
      source.connect(gain);
      gain.connect(context.destination);
      source.onended = resolve;
      source.start(0);
      window.setTimeout(resolve, Math.max(250, buffer.duration * 1000 + 100));
    } catch (error) {
      reject(error);
    }
  });
}

async function playSound(soundKey, repeat = 1) {
  if (!soundsEnabled) {
    $('#soundStatus').textContent = 'Sounds off';
    return false;
  }

  const ready = await prepareSounds();
  if (!ready) return false;

  const context = getAudioContext();
  if (context.state === 'suspended') {
    await context.resume();
  }

  const buffer = decodedSounds.get(soundKey);
  if (!buffer) {
    setStatus(`Sound file missing: ${soundKey}`);
    return false;
  }

  try {
    for (let i = 0; i < repeat; i += 1) {
      await playDecodedBuffer(buffer);
    }
    $('#soundStatus').textContent = 'Sounds enabled';
    return true;
  } catch (error) {
    $('#soundStatus').textContent = 'Sound playback failed';
    setStatus(`Sound playback failed: ${error.message || error}`);
    return false;
  }
}

function setStatus(message) {
  $('#statusBar').textContent = message;
}

function setClock() {
  const now = new Date();
  $('#currentClock').textContent = now.toLocaleTimeString([], { hour: 'numeric', minute: '2-digit' });
}

function renderScoreboard() {
  const scores = computeScoreboard(simulator.completedCars);
  const mappings = [
    ['order1', '#avgOrder1', '#pctOrder1'],
    ['order2', '#avgOrder2', '#pctOrder2'],
    ['cash', '#avgCash', '#pctCash'],
    ['present', '#avgPresent', '#pctPresent'],
    ['total', '#avgTotal', '#pctTotal'],
  ];
  for (const [key, avgSelector, pctSelector] of mappings) {
    const data = scores[key];
    const avgEl = $(avgSelector);
    avgEl.textContent = formatTime(data.avg);
    avgEl.className = `avg ${avgClassForKey(key, data.avg)}`;
    const pctEl = $(pctSelector);
    pctEl.textContent = `${data.pct}%`;
    pctEl.className = `pct ${statusColourForPct(data.pct)}`;
  }
}

function setReadyTick(selector, visible) {
  const tick = $(selector);
  if (!tick) return;
  tick.classList.toggle('is-hidden', !visible);
}

function renderLiveSectionLabels() {
  const labels = {
    present: simulator.carAt('present'),
    cash: simulator.carAt('cash'),
    order1: simulator.carAt('order1'),
    order2: simulator.carAt('order2'),
  };
  $('#labelPresentTime').textContent = labels.present ? formatTime(simulator.stationElapsed(labels.present)) : '0:00';
  $('#labelCashTime').textContent = labels.cash ? formatTime(simulator.stationElapsed(labels.cash)) : '0:00';
  $('#labelOrder1Time').textContent = labels.order1 ? formatTime(simulator.stationElapsed(labels.order1)) : '0:00';
  $('#labelOrder2Time').textContent = labels.order2 ? formatTime(simulator.stationElapsed(labels.order2)) : '0:00';
  setReadyTick('#tickCash', Boolean(labels.cash && labels.cash.releaseRequested));
  setReadyTick('#tickOrder1', Boolean(labels.order1 && labels.order1.releaseRequested));
  setReadyTick('#tickOrder2', Boolean(labels.order2 && labels.order2.releaseRequested));
}


function renderSummaryPanel() {
  $('#carsInLane').textContent = String(simulator.getCarsInLaneCount());
  const longest = simulator.getLongestCurrentTotal();
  const longestWait = $('#longestWait');
  longestWait.textContent = formatTime(longest);
  longestWait.className = `status-${statusFromTotal(longest)}`;
}

function renderControlsState() {
  $('#btnReleaseOrder1').disabled = !simulator.carAt('order1');
  $('#btnReleaseOrder2').disabled = !simulator.carAt('order2');
  $('#btnReleaseCash').disabled = !simulator.carAt('cash');
  $('#btnReleasePresent').disabled = !simulator.carAt('present');
}


function renderCars() {
  const layer = $('#carsLayer');
  layer.innerHTML = '';
  for (const car of simulator.activeCars) {
    const ui = POSITION_UI[car.position];
    if (!ui) continue;
    const status = carStatus(car);
    const wrapper = document.createElement('div');
    wrapper.className = 'car';
    wrapper.style.left = `${(ui.x / MAP_SIZE.width) * 100}%`;
    wrapper.style.top = `${(ui.y / MAP_SIZE.height) * 100}%`;
    wrapper.style.transform = `translate(-50%, -50%) rotate(${ui.rotation}deg)`;
    wrapper.innerHTML = `
      <img src="${carImageForStatus(status)}" alt="Car ${car.id}" onerror="this.parentElement.classList.add('asset-missing'); this.remove();">
      <div class="car-badge">${car.id}</div>
    `;
    layer.appendChild(wrapper);
  }
}

function renderHistory() {
  const body = $('#historyBody');
  if (!simulator.completedCars.length) {
    body.innerHTML = '<tr><td colspan="6" class="empty">No completed cars yet.</td></tr>';
    return;
  }
  body.innerHTML = simulator.completedCars.slice(0, 12).map((car) => `
    <tr>
      <td>#${car.id}</td>
      <td>${car.lane}</td>
      <td>${formatTime(car.lane === 1 ? car.timings.order1 : car.timings.order2)}</td>
      <td>${formatTime(car.timings.cash)}</td>
      <td>${formatTime(car.timings.present)}</td>
      <td>${formatTime(car.timings.total)}</td>
    </tr>
  `).join('');
}

function renderTargets() {
  $('#goalOrder1').textContent = formatTime(TARGETS.order1);
  $('#goalOrder2').textContent = formatTime(TARGETS.order2);
  $('#goalCash').textContent = formatTime(TARGETS.cash);
  $('#goalPresent').textContent = formatTime(TARGETS.present);
  $('#goalTotal').textContent = formatTime(TARGETS.total);
}

function render() {
  setClock();
  renderTargets();
  renderScoreboard();
  renderLiveSectionLabels();
  renderSummaryPanel();
  if ($('#completedCount')) $('#completedCount').textContent = String(simulator.completedCars.length);
  renderCars();
  renderHistory();
  renderControlsState();
  if (!soundsEnabled) $('#soundStatus').textContent = 'Sounds off';
  else if (soundReady) $('#soundStatus').textContent = 'Sounds enabled';
  else $('#soundStatus').textContent = 'Sounds ready after first click';
}

async function handleEvents(events) {
  for (const event of events) {
    if (event.type === 'lane1-entry') {
      await playSound('lane1Entry');
    }
    if (event.type === 'lane2-entry') {
      await playSound('lane2Entry');
    }
    if (event.type === 'yellow-threshold') {
      await playSound('yellow');
      setStatus(`Car #${event.carId} turned yellow at 1:30 total time.`);
    }
    if (event.type === 'red-threshold') {
      await playSound('red', 2);
      setStatus(`Car #${event.carId} turned red at 2:00 total time.`);
    }
    if (event.type === 'car-completed') {
      setStatus(`Car #${event.carId} left present and was counted as a completed car.`);
    }
  }
}

async function addCar(lane) {
  const result = simulator.addCar(lane);
  if (!result.ok) {
    setStatus(result.reason);
    return;
  }
  saveState();
  render();
  await handleEvents(result.events || []);
}

function releaseStation(station) {
  const result = simulator.releaseStation(station);
  setStatus(result.reason || simulator.statusMessage);
  saveState();
  render();
}


function resetDay() {
  if (!window.confirm('Reset all active cars, averages and completed history?')) return;
  simulator.reset();
  localStorage.removeItem(STORAGE_KEY);
  saveState();
  setStatus('Day reset.');
  render();
}

async function runTick() {
  const events = simulator.tick(1);
  saveState();
  render();
  await handleEvents(events);
}


function setFullscreenState(isFullscreen) {
  document.body.classList.toggle('fullscreen-mode', isFullscreen);
  const button = $('#btnFullscreen');
  if (button) button.textContent = isFullscreen ? 'Exit Fullscreen' : 'Fullscreen Mode';
}

async function toggleFullscreen() {
  try {
    if (document.fullscreenElement) {
      await document.exitFullscreen();
    } else {
      await document.documentElement.requestFullscreen();
    }
  } catch (error) {
    setStatus(`Fullscreen could not be changed: ${error.message || error}`);
  }
}

function handleFullscreenChange() {
  setFullscreenState(Boolean(document.fullscreenElement));
}

function wireButtons() {
  $('#btnAddLane1').addEventListener('click', () => addCar(1));
  $('#btnAddLane2').addEventListener('click', () => addCar(2));
  $('#btnReleaseOrder1').addEventListener('click', () => releaseStation('order1'));
  $('#btnReleaseOrder2').addEventListener('click', () => releaseStation('order2'));
  $('#btnReleaseCash').addEventListener('click', () => releaseStation('cash'));
  $('#btnReleasePresent').addEventListener('click', () => releaseStation('present'));
  $('#btnEnableSounds').addEventListener('click', enableSounds);
  $('#btnFullscreen').addEventListener('click', toggleFullscreen);
  $('#btnExitFullscreen').addEventListener('click', toggleFullscreen);
  $('#btnTestSounds').addEventListener('click', async () => {
    await enableSounds();
    await playSound('lane1Entry');
    await playSound('lane2Entry');
    await playSound('yellow');
    await playSound('red', 2);
    setStatus('Played all test sounds: Lane 1, Lane 2, yellow, and red twice.');
  });
  $('#btnReset').addEventListener('click', resetDay);

  document.addEventListener('keydown', (event) => {
    const key = event.key.toLowerCase();
    if (key === '1') addCar(1);
    if (key === '2') addCar(2);
    if (key === 'q') releaseStation('order1');
    if (key === 'w') releaseStation('order2');
    if (key === 'c') releaseStation('cash');
    if (key === 'p') releaseStation('present');
    if (key === 'f') toggleFullscreen();
  });
}

document.addEventListener('fullscreenchange', handleFullscreenChange);

wireButtons();
setFullscreenState(Boolean(document.fullscreenElement));
setStatus(simulator.statusMessage || 'Ready.');
render();
setInterval(runTick, 1000);
setInterval(setClock, 30000);
